def number_sign(number):
    if number < 0:
        return 'Negative'
    return 'Non-negative'

def divisibility_by_three(number):
    if number % 3 == 0:
        return 'Divisible by 3'
    return 'Not divisible by 3'

def compare_numbers(a, b):
    if a > b:
        return 'greater'
    elif a == b:
        return 'equal'
    else:
        return 'less'

def water_state(temperature):
    if temperature < 0:
        return 'solid'
    elif temperature <= 100:
        return 'liquid'
    else:
        return 'gas'

def ticket_price(age):
    if age < 13:
        return 5
    elif age <= 17:
        return 8
    elif age <= 64:
        return 12
    else:
        return 6

def get_letter_grade(score):
    if score >= 90:
        return 'A'
    elif score >= 80:
        return 'B'
    elif score >= 70:
        return 'C'
    elif score >= 60:
        return 'D'
    else:
        return 'F'

def check_password(password):
    if len(password) >= 8:
        return 'Valid'
    return 'Too short'

def fizz_buzz(n):
    if n % 3 == 0 and n % 5 == 0:
        return 'FizzBuzz'
    elif n % 3 == 0:
        return 'Fizz'
    elif n % 5 == 0:
        return 'Buzz'
    else:
        return str(n)

def sum_numbers(n):
    total = 0
    for i in range(1, n + 1):
        total += i
    return total

def multiply_range(start, end):
    product = 1
    for i in range(start, end + 1):
        product *= i
    return product

def repeat_char(char, n):
    result = ''
    for i in range(n):
        result += char
    return result

def sum_even_numbers(n):
    total = 0
    for i in range(2, n + 1, 2):
        total += i
    return total

def count_munchkins(heights):
    count = 0
    for h in heights:
        if h < 48:
            count += 1
    return count

def reverse_string(text):
    reversed_text = ''
    for char in text:
        reversed_text = char + reversed_text
    return reversed_text

def sum_digits(number):
    total = 0
    while number > 0:
        total += number % 10
        number //= 10
    return total
